import React, { useCallback, useEffect, useRef, useState } from "react";
import { WeakEdge, getAllMembers } from "./groupUtils";

interface Props {
  nodes: string[];
  edges: WeakEdge[];
  onEdgesChanged: (edges: WeakEdge[]) => void;
  nodeColors: Map<string, string>;
}

interface NodePosition {
  x: number;
  y: number;
}

const NODE_WIDTH = 120;
const LINE_HEIGHT = 22;
const NODE_PADDING_Y = 14;
const PADDING = 60;

// Force simulation parameters
const REPULSION = 8000;
const EDGE_SPRING = 0.03;
const EDGE_REST_LENGTH = 160;
const DAMPING = 0.85;
const MIN_VELOCITY = 0.1;
const CENTER_GRAVITY = 0.005;

function getNodeHeight(node: string): number {
  const members = getAllMembers(node);
  return members.length * LINE_HEIGHT + NODE_PADDING_Y * 2;
}

function getNodeWidth(node: string): number {
  const members = getAllMembers(node);
  return Math.max(NODE_WIDTH, Math.max(...members.map((m) => m.length)) * 8 + 20);
}

function layoutNodes(nodes: string[]): Map<string, NodePosition> {
  const positions = new Map<string, NodePosition>();
  const cols = Math.ceil(Math.sqrt(nodes.length));
  const spacingX = NODE_WIDTH + PADDING;
  const spacingY = 80 + PADDING;

  nodes.forEach((node, i) => {
    const col = i % cols;
    const row = Math.floor(i / cols);
    positions.set(node, {
      x: PADDING + col * spacingX + NODE_WIDTH / 2,
      y: PADDING + row * spacingY + 40,
    });
  });

  return positions;
}

function edgeKey(a: string, b: string): string {
  return a < b ? `${a}||${b}` : `${b}||${a}`;
}

function hasEdge(edges: WeakEdge[], a: string, b: string): boolean {
  return edges.some(
    ([x, y]) => (x === a && y === b) || (x === b && y === a)
  );
}

export function WeakGraph({ nodes, edges, onEdgesChanged, nodeColors }: Props) {
  const [selected, setSelected] = useState<string | null>(null);
  const [dragging, setDragging] = useState<string | null>(null);
  const positionsRef = useRef<Map<string, NodePosition>>(layoutNodes(nodes));
  const velocitiesRef = useRef<Map<string, NodePosition>>(new Map());
  const [renderTick, setRenderTick] = useState(0);
  const animFrameRef = useRef<number>(0);
  const svgRef = useRef<SVGSVGElement>(null);
  const dragStart = useRef<{ x: number; y: number } | null>(null);
  const dragOriginal = useRef<NodePosition | null>(null);
  const draggingRef = useRef<string | null>(null);
  const edgesChangedAtRef = useRef<number>(0);

  // Keep draggingRef in sync
  useEffect(() => {
    draggingRef.current = dragging;
  }, [dragging]);

  // Track when edges change
  useEffect(() => {
    edgesChangedAtRef.current = Date.now();
  }, [edges]);

  // Add new nodes and remove stale ones
  useEffect(() => {
    const pos = positionsRef.current;
    const vel = velocitiesRef.current;
    const cols = Math.ceil(Math.sqrt(nodes.length));
    const spacingX = NODE_WIDTH + PADDING;
    const spacingY = 80 + PADDING;

    nodes.forEach((node, i) => {
      if (!pos.has(node)) {
        const col = i % cols;
        const row = Math.floor(i / cols);
        pos.set(node, {
          x: PADDING + col * spacingX + NODE_WIDTH / 2,
          y: PADDING + row * spacingY + 40,
        });
        vel.set(node, { x: 0, y: 0 });
      }
    });

    Array.from(pos.keys()).forEach((key) => {
      if (!nodes.includes(key)) {
        pos.delete(key);
        vel.delete(key);
      }
    });
  }, [nodes]);

  // Initialize velocities
  useEffect(() => {
    const vel = velocitiesRef.current;
    nodes.forEach((node) => {
      if (!vel.has(node)) {
        vel.set(node, { x: 0, y: 0 });
      }
    });
  }, [nodes]);

  // Force simulation loop
  useEffect(() => {
    let running = true;
    let settledFrames = 0;

    function simulate() {
      if (!running) return;

      const pos = positionsRef.current;
      const vel = velocitiesRef.current;
      const currentDragging = draggingRef.current;

      if (nodes.length === 0) {
        animFrameRef.current = requestAnimationFrame(simulate);
        return;
      }

      // Compute center of mass
      let cx = 0, cy = 0;
      nodes.forEach((node) => {
        const p = pos.get(node);
        if (p) { cx += p.x; cy += p.y; }
      });
      cx /= nodes.length;
      cy /= nodes.length;

      // Target center
      const targetCx = 400;
      const targetCy = 300;

      let totalMovement = 0;

      // Compute forces
      const forces = new Map<string, { fx: number; fy: number }>();
      nodes.forEach((node) => forces.set(node, { fx: 0, fy: 0 }));

      // Repulsion between all pairs
      for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
          const a = nodes[i];
          const b = nodes[j];
          const pa = pos.get(a);
          const pb = pos.get(b);
          if (!pa || !pb) continue;

          let dx = pa.x - pb.x;
          let dy = pa.y - pb.y;
          let dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 1) { dx = Math.random() - 0.5; dy = Math.random() - 0.5; dist = 1; }

          const force = REPULSION / (dist * dist);

          // Overlap penalty ramps up over 1s after edges change
          const msSinceEdgeChange = Date.now() - edgesChangedAtRef.current;
          const overlapStrength = Math.min(1, msSinceEdgeChange / 1000);
          const minDist = (getNodeWidth(a) + getNodeWidth(b)) / 2 + 20;
          const overlap = dist < minDist ? (minDist - dist) * 0.5 * overlapStrength : 0;

          const totalForce = force + overlap;
          const fx = (dx / dist) * totalForce;
          const fy = (dy / dist) * totalForce;

          forces.get(a)!.fx += fx;
          forces.get(a)!.fy += fy;
          forces.get(b)!.fx -= fx;
          forces.get(b)!.fy -= fy;
        }
      }

      // Edge attraction (spring)
      edges.forEach(([a, b]) => {
        const pa = pos.get(a);
        const pb = pos.get(b);
        if (!pa || !pb) return;

        const dx = pb.x - pa.x;
        const dy = pb.y - pa.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 1) return;

        const displacement = dist - EDGE_REST_LENGTH;
        const force = EDGE_SPRING * displacement;

        const fx = (dx / dist) * force;
        const fy = (dy / dist) * force;

        const fa = forces.get(a);
        const fb = forces.get(b);
        if (fa) { fa.fx += fx; fa.fy += fy; }
        if (fb) { fb.fx -= fx; fb.fy -= fy; }
      });

      // Center gravity
      nodes.forEach((node) => {
        const p = pos.get(node);
        const f = forces.get(node);
        if (!p || !f) return;
        f.fx += (targetCx - p.x) * CENTER_GRAVITY;
        f.fy += (targetCy - p.y) * CENTER_GRAVITY;
      });

      // Apply forces to velocities and positions
      nodes.forEach((node) => {
        if (node === currentDragging) return; // Don't move dragged node

        const p = pos.get(node);
        const v = vel.get(node) || { x: 0, y: 0 };
        const f = forces.get(node);
        if (!p || !f) return;

        v.x = (v.x + f.fx) * DAMPING;
        v.y = (v.y + f.fy) * DAMPING;

        // Clamp velocity
        const speed = Math.sqrt(v.x * v.x + v.y * v.y);
        if (speed > 50) {
          v.x = (v.x / speed) * 50;
          v.y = (v.y / speed) * 50;
        }

        p.x += v.x;
        p.y += v.y;

        // Keep within bounds
        const w = getNodeWidth(node) / 2;
        const h = getNodeHeight(node) / 2;
        p.x = Math.max(w + 10, p.x);
        p.y = Math.max(h + 10, p.y);

        vel.set(node, v);
        totalMovement += Math.abs(v.x) + Math.abs(v.y);
      });

      // Only re-render if there's meaningful movement
      if (totalMovement > MIN_VELOCITY * nodes.length) {
        settledFrames = 0;
        setRenderTick((t) => t + 1);
      } else {
        settledFrames++;
        // Still render occasionally to catch up
        if (settledFrames < 10) {
          setRenderTick((t) => t + 1);
        }
      }

      animFrameRef.current = requestAnimationFrame(simulate);
    }

    animFrameRef.current = requestAnimationFrame(simulate);

    return () => {
      running = false;
      cancelAnimationFrame(animFrameRef.current);
    };
  }, [nodes, edges]);

  const positions = positionsRef.current;

  // Compute SVG dimensions from positions
  let maxRight = 400;
  let maxBottom = 300;
  nodes.forEach((node) => {
    const pos = positions.get(node);
    if (pos) {
      maxRight = Math.max(maxRight, pos.x + getNodeWidth(node) / 2 + PADDING);
      maxBottom = Math.max(maxBottom, pos.y + getNodeHeight(node) / 2 + PADDING);
    }
  });
  const svgWidth = maxRight;
  const svgHeight = maxBottom;

  const handleNodeClick = useCallback(
    (node: string) => {
      if (selected === null) {
        setSelected(node);
      } else if (selected === node) {
        setSelected(null);
      } else {
        if (hasEdge(edges, selected, node)) {
          onEdgesChanged(
            edges.filter(
              ([a, b]) =>
                !(
                  (a === selected && b === node) ||
                  (a === node && b === selected)
                )
            )
          );
        } else {
          onEdgesChanged([...edges, [selected, node]]);
        }
        setSelected(null);
      }
    },
    [selected, edges, onEdgesChanged]
  );

  const handleEdgeClick = useCallback(
    (a: string, b: string, e: React.MouseEvent) => {
      e.stopPropagation();
      onEdgesChanged(
        edges.filter(
          ([x, y]) => !((x === a && y === b) || (x === b && y === a))
        )
      );
      setSelected(null);
    },
    [edges, onEdgesChanged]
  );

  const handleMouseDown = useCallback(
    (node: string, e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      const pos = positionsRef.current.get(node);
      if (!pos) return;
      dragStart.current = { x: e.clientX, y: e.clientY };
      dragOriginal.current = { ...pos };
      // Zero out velocity for dragged node
      velocitiesRef.current.set(node, { x: 0, y: 0 });
      setDragging(node);
    },
    []
  );

  const handleMouseMove = useCallback(
    (e: React.MouseEvent) => {
      if (!dragging || !dragStart.current || !dragOriginal.current) return;
      const dx = e.clientX - dragStart.current.x;
      const dy = e.clientY - dragStart.current.y;
      positionsRef.current.set(dragging, {
        x: dragOriginal.current.x + dx,
        y: dragOriginal.current.y + dy,
      });
      velocitiesRef.current.set(dragging, { x: 0, y: 0 });
      setRenderTick((t) => t + 1);
    },
    [dragging]
  );

  const handleMouseUp = useCallback(() => {
    if (dragging && dragStart.current) {
      const threshold = 5;
      const pos = positionsRef.current.get(dragging);
      if (
        pos &&
        dragOriginal.current &&
        Math.abs(pos.x - dragOriginal.current.x) < threshold &&
        Math.abs(pos.y - dragOriginal.current.y) < threshold
      ) {
        handleNodeClick(dragging);
      }
      // Zero velocity so it settles from where it was dropped
      velocitiesRef.current.set(dragging, { x: 0, y: 0 });
    }
    setDragging(null);
    dragStart.current = null;
    dragOriginal.current = null;
  }, [dragging, handleNodeClick]);

  return (
    <div style={{ margin: "20px 0" }}>
      <div style={{ fontSize: "0.85rem", color: "#666", marginBottom: "8px" }}>
        Click a node, then click another to connect them. Click a connection line to remove it. Drag nodes to rearrange.
      </div>
      <svg
        ref={svgRef}
        width={svgWidth}
        height={svgHeight}
        style={{
          border: "1px solid #ddd",
          borderRadius: "8px",
          background: "#fafafa",
          userSelect: "none",
        }}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        {/* Edges */}
        {edges.map(([a, b]) => {
          const posA = positions.get(a);
          const posB = positions.get(b);
          if (!posA || !posB) return null;
          return (
            <line
              key={edgeKey(a, b)}
              x1={posA.x}
              y1={posA.y}
              x2={posB.x}
              y2={posB.y}
              stroke="#FFB347"
              strokeWidth={3}
              strokeDasharray="8,4"
              style={{ cursor: "pointer" }}
              onClick={(e) => handleEdgeClick(a, b, e)}
            />
          );
        })}

        {/* Edge click targets (wider invisible lines for easier clicking) */}
        {edges.map(([a, b]) => {
          const posA = positions.get(a);
          const posB = positions.get(b);
          if (!posA || !posB) return null;
          return (
            <line
              key={`hit-${edgeKey(a, b)}`}
              x1={posA.x}
              y1={posA.y}
              x2={posB.x}
              y2={posB.y}
              stroke="transparent"
              strokeWidth={16}
              style={{ cursor: "pointer" }}
              onClick={(e) => handleEdgeClick(a, b, e)}
            />
          );
        })}

        {/* Nodes */}
        {nodes.map((node) => {
          const pos = positions.get(node);
          if (!pos) return null;
          const isSelected = selected === node;
          const members = getAllMembers(node);
          const nodeH = getNodeHeight(node);
          const width = getNodeWidth(node);
          const textStartY = pos.y - (members.length - 1) * LINE_HEIGHT / 2;

          return (
            <g
              key={node}
              style={{ cursor: dragging === node ? "grabbing" : "grab" }}
              onMouseDown={(e) => handleMouseDown(node, e)}
            >
              <rect
                x={pos.x - width / 2}
                y={pos.y - nodeH / 2}
                width={width}
                height={nodeH}
                rx={8}
                ry={8}
                fill={isSelected ? "#E8F4FD" : (nodeColors.get(node) || "#fff")}
                stroke={isSelected ? "#4c9ffe" : "#ccc"}
                strokeWidth={isSelected ? 3 : 1.5}
                style={{ filter: "drop-shadow(0 1px 2px rgba(0,0,0,0.1))" }}
              />
              <text
                x={pos.x}
                y={textStartY}
                textAnchor="middle"
                dominantBaseline="central"
                fontSize={14}
                fill="#333"
                pointerEvents="none"
              >
                {members.map((member, i) => (
                  <tspan key={i} x={pos.x} dy={i === 0 ? 0 : LINE_HEIGHT}>
                    {member}
                  </tspan>
                ))}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
