import React, { useCallback, useEffect, useRef, useState } from "react";
import { createPortal } from "react-dom";

import {
  Active,
  closestCenter,
  CollisionDetection,
  DragOverlay,
  DndContext,
  DropAnimation,
  KeyboardSensor,
  KeyboardCoordinateGetter,
  Modifiers,
  MouseSensor,
  MeasuringConfiguration,
  PointerActivationConstraint,
  ScreenReaderInstructions,
  TouchSensor,
  UniqueIdentifier,
  useSensor,
  useSensors,
  defaultDropAnimationSideEffects,
  CollisionDescriptor,
} from "@dnd-kit/core";
import {
  arrayMove,
  useSortable,
  SortableContext,
  sortableKeyboardCoordinates,
  SortingStrategy,
  rectSortingStrategy,
  AnimateLayoutChanges,
  NewIndexGetter,
} from "@dnd-kit/sortable";

import { ClientRect } from "@dnd-kit/core/dist/types";

import { Item, List, Wrapper } from "./components";
import { Coordinates } from "@dnd-kit/utilities";
import { groupSize, mergeItems, ungroupItem } from "./groupUtils";

export interface Props {
  activationConstraint?: PointerActivationConstraint;
  animateLayoutChanges?: AnimateLayoutChanges;
  adjustScale?: boolean;
  coordinateGetter?: KeyboardCoordinateGetter;
  Container?: any; // To-do: Fix me
  dropAnimation?: DropAnimation | null;
  getNewIndex?: NewIndexGetter;
  handle?: boolean;
  itemCount?: number;
  items: string[];
  measuring?: MeasuringConfiguration;
  modifiers?: Modifiers;
  renderItem?: any;
  removable?: boolean;
  reorderItems?: typeof arrayMove;
  strategy?: SortingStrategy;
  style?: React.CSSProperties;
  useDragOverlay?: boolean;
  getItemStyles?(args: {
    id: UniqueIdentifier;
    index: number;
    isSorting: boolean;
    isDragOverlay: boolean;
    overIndex: number;
    isDragging: boolean;
  }): React.CSSProperties;
  wrapperStyle?(args: {
    active: Pick<Active, "id"> | null;
    index: number;
    isDragging: boolean;
    id: UniqueIdentifier;
  }): React.CSSProperties;
  isDisabled?(id: UniqueIdentifier): boolean;
  onItemsChanged: React.Dispatch<React.SetStateAction<string[]>>;
}

const dropAnimationConfig: DropAnimation = {
  sideEffects: defaultDropAnimationSideEffects({
    styles: {
      active: {
        opacity: "0.5",
      },
    },
  }),
};

const screenReaderInstructions: ScreenReaderInstructions = {
  draggable: `
    To pick up a sortable item, press the space bar.
    While sorting, use the arrow keys to move the item.
    Press space again to drop the item in its new position, or press escape to cancel.
  `,
};

function sortCollisionsAsc(
  { data: { value: a } }: CollisionDescriptor,
  { data: { value: b } }: CollisionDescriptor
) {
  return a - b;
}

function centerOfRectangle(
  rect: ClientRect,
  left = rect.left,
  top = rect.top
): Coordinates {
  return {
    x: left + rect.width * 0.5,
    y: top + rect.height * 0.5,
  };
}

function distanceBetween(p1: Coordinates, p2: Coordinates) {
  return Math.sqrt(Math.pow(p1.x - p2.x, 2) + Math.pow(p1.y - p2.y, 2));
}

function isHovered(
  pointer: Coordinates | null,
  clientRect: DOMRect | undefined
) {
  if (!pointer || !clientRect) {
    return false;
  }

  return (
    pointer.x > clientRect.x &&
    pointer.x < clientRect.x + clientRect.width &&
    pointer.y > clientRect.y &&
    pointer.y < clientRect.y + clientRect.height
  );
}

export function Sortable({
  activationConstraint,
  animateLayoutChanges,
  adjustScale = false,
  Container = List,
  coordinateGetter = sortableKeyboardCoordinates,
  dropAnimation = dropAnimationConfig,
  getItemStyles = () => ({}),
  getNewIndex,
  handle = false,
  items: initialItems,
  isDisabled = () => false,
  measuring,
  modifiers,
  removable,
  renderItem,
  reorderItems = arrayMove,
  strategy = rectSortingStrategy,
  style,
  useDragOverlay = true,
  wrapperStyle = () => ({}),
  onItemsChanged,
}: Props) {
  const [activeId, setActiveId] = useState<UniqueIdentifier | null>(null);
  const sensors = useSensors(
    useSensor(MouseSensor, {
      activationConstraint,
    }),
    useSensor(TouchSensor, {
      activationConstraint,
    }),
    useSensor(KeyboardSensor, {
      // Disable smooth scrolling in Cypress automated tests
      scrollBehavior: "Cypress" in window ? "auto" : undefined,
      coordinateGetter,
    })
  );
  const getIndex = (id: UniqueIdentifier) =>
    initialItems.indexOf(id.toString());
  const activeIndex = activeId != null ? getIndex(activeId) : -1;
  const handleRemove = removable
    ? (id: UniqueIdentifier) =>
        onItemsChanged((items) => items.filter((item) => item !== id))
    : undefined;

  const handleUngroup = (id: UniqueIdentifier) => {
    const idStr = id.toString();
    const parts = ungroupItem(idStr);
    if (parts.length <= 1) return;
    onItemsChanged((items) => {
      const index = items.indexOf(idStr);
      if (index === -1) return items;
      const newItems = [...items];
      newItems.splice(index, 1, ...parts);
      return newItems;
    });
  };

  let previousValue: CollisionDescriptor[] = [];
  let initialValue: CollisionDescriptor[] = [];

  const collisionDetectionStrategy: CollisionDetection = useCallback(
    (args) => {
      const centerRect = centerOfRectangle(
        args.collisionRect,
        args.collisionRect.left,
        args.collisionRect.top
      );

      const currentIndex = initialValue.findIndex(
        (v) => v.id === args.active.id
      );
      const currentId = previousValue[currentIndex]?.id || args.active.id;
      let collisions: CollisionDescriptor[] = [];

      const currentRect = args.droppableRects.get(currentId);

      const centerCurrectRect = currentRect
        ? centerOfRectangle(currentRect)
        : { x: 0, y: 0 };

      const spaceSize = 16;
      const isEnabled =
        Math.abs(centerCurrectRect.x - centerRect.x) >
          args.collisionRect.width + spaceSize ||
        Math.abs(centerCurrectRect.y - centerRect.y) >
          args.collisionRect.height + spaceSize;

      for (const droppableContainer of args.droppableContainers) {
        const { id } = droppableContainer;
        const rect = args.droppableRects.get(id);
        const clientRect =
          droppableContainer.node.current?.getBoundingClientRect();

        if (rect) {
          let distBetween = distanceBetween(
            centerOfRectangle(rect),
            isEnabled ? centerRect : centerCurrectRect
          );

          collisions.push({
            id,
            data: {
              droppableContainer,
              value: distBetween,
              hovered:
                args.active.id !== id
                  ? isHovered(args.pointerCoordinates, clientRect)
                  : false,
            },
          });
        }
      }

      previousValue = collisions.sort(sortCollisionsAsc);

      if (initialValue.length === 0) {
        initialValue = previousValue;
      }

      return previousValue;
    },
    [activeId, initialItems]
  );

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={collisionDetectionStrategy}
      onDragStart={({ active }) => {
        if (!active) {
          return;
        }

        setActiveId(active.id);
      }}
      onDragEnd={({ active, over, collisions }) => {
        const hovered = collisions?.find(
          (collision) => collision?.data?.hovered
        );
        console.log("active: " + active.id);
        console.log("hovered: " + hovered?.id);

        setActiveId(null);

        if (hovered) {
          let newItems = initialItems.filter((item) => item !== hovered.id);
          newItems[newItems.indexOf(active.id.toString())] =
            mergeItems(active.id.toString(), hovered.id.toString());
          onItemsChanged(newItems);
        } else if (over) {
          const overIndex = getIndex(over.id);
          if (activeIndex !== overIndex) {
            onItemsChanged((items) =>
              reorderItems(items, activeIndex, overIndex)
            );
          }
        }
      }}
      onDragCancel={() => setActiveId(null)}
      measuring={measuring}
      modifiers={modifiers}
    >
      <Wrapper style={style} center>
        <SortableContext items={initialItems} strategy={strategy}>
          <Container>
            {initialItems.map((value, index) => (
              <SortableItem
                key={value}
                id={value}
                handle={handle}
                index={index}
                style={() => ({
                  gridColumn: "span " + groupSize(value),
                })}
                wrapperStyle={wrapperStyle}
                disabled={isDisabled(value)}
                renderItem={renderItem}
                onRemove={handleRemove}
                onUngroup={handleUngroup}
                animateLayoutChanges={animateLayoutChanges}
                useDragOverlay={useDragOverlay}
                getNewIndex={getNewIndex}
              />
            ))}
          </Container>
        </SortableContext>
      </Wrapper>
      {useDragOverlay
        ? createPortal(
            <DragOverlay
              adjustScale={adjustScale}
              dropAnimation={dropAnimation}
            >
              {activeId != null ? (
                <Item
                  value={initialItems[activeIndex]}
                  style={getItemStyles({
                    id: initialItems[activeIndex],
                    index: activeIndex,
                    isSorting: activeId !== null,
                    isDragging: true,
                    overIndex: -1,
                    isDragOverlay: true,
                  })}
                  dragOverlay
                />
              ) : null}
            </DragOverlay>,
            document.body
          )
        : null}
    </DndContext>
  );
}

interface SortableItemProps {
  animateLayoutChanges?: AnimateLayoutChanges;
  disabled?: boolean;
  getNewIndex?: NewIndexGetter;
  id: UniqueIdentifier;
  index: number;
  handle: boolean;
  useDragOverlay?: boolean;
  onRemove?(id: UniqueIdentifier): void;
  onUngroup?(id: UniqueIdentifier): void;
  style(values: any): React.CSSProperties;
  renderItem?(args: any): React.ReactElement;
  wrapperStyle: Props["wrapperStyle"];
}

export function SortableItem({
  disabled,
  animateLayoutChanges,
  getNewIndex,
  handle,
  id,
  index,
  onRemove,
  onUngroup,
  style,
  renderItem,
  useDragOverlay,
  wrapperStyle,
}: SortableItemProps) {
  const {
    active,
    attributes,
    isDragging,
    isSorting,
    listeners,
    overIndex,
    setNodeRef,
    setActivatorNodeRef,
    transform,
    transition,
  } = useSortable({
    id,
    animateLayoutChanges,
    disabled,
    getNewIndex,
  });

  return (
    <Item
      ref={setNodeRef}
      value={id.toString()}
      dragging={isDragging}
      sorting={isSorting}
      index={index}
      style={style({
        index,
        id,
        isDragging,
        isSorting,
        overIndex,
      })}
      onRemove={onRemove ? () => onRemove(id) : undefined}
      onUngroup={onUngroup ? () => onUngroup(id) : undefined}
      transform={isDragging ? transform : undefined}
      transition={isDragging ? transition : undefined}
      listeners={listeners}
      data-index={index}
      data-id={id}
      dragOverlay={!useDragOverlay && isDragging}
      {...attributes}
    />
  );
}
