import React, { useEffect, useState } from "react";
import "./App.css";
import PlainTextForm from "./PlainTextForm";
import { Tables, TablesComponent } from "./TablesComponent";
import { Sortable, Props as SortableProps } from "./Sortable";
import { GridContainer } from "./components";
import { rectSortingStrategy } from "@dnd-kit/sortable";
import * as XLSX from "xlsx";
import { groupSize, getAllMembers, WeakEdge } from "./groupUtils";
import { useGroupColors } from "./groupColors";
import { WeakGraph } from "./WeakGraph";
import { guestsToTables } from "./tableSolver";

function loadState() {
  try {
    const saved = localStorage.getItem("seating-chart-state");
    if (saved) return JSON.parse(saved);
  } catch {}
  return null;
}

function saveState(
  guests: string[],
  tableSize: number,
  tables: Tables | null,
  weakEdges: WeakEdge[]
) {
  localStorage.setItem(
    "seating-chart-state",
    JSON.stringify({ guests, tableSize, tables, weakEdges })
  );
}

function App() {
  const saved = loadState();
  const [guests, setGuests] = useState<string[]>(saved?.guests ?? []);
  const [tableSize, setTableSize] = useState<number>(saved?.tableSize ?? 8);
  const [tables, setTables] = useState<Tables | null>(saved?.tables ?? null);
  const [weakEdges, setWeakEdges] = useState<WeakEdge[]>(
    saved?.weakEdges ?? []
  );

  useEffect(() => {
    saveState(guests, tableSize, tables, weakEdges);
  }, [guests, tableSize, tables, weakEdges]);

  const [phase, setPhase] = useState<"strong" | "weak">("strong");
  const [tablesKey, setTablesKey] = useState(0);

  const nodeColors = useGroupColors(guests, weakEdges);

  const clearProgress = () => {
    localStorage.removeItem("seating-chart-state");
    setGuests([]);
    setTableSize(8);
    setTables(null);
    setWeakEdges([]);
    setPhase("strong");
  };

  const props: Partial<SortableProps> = {
    adjustScale: true,
    Container: (props: any) => <GridContainer {...props} columns={20} />,
    strategy: rectSortingStrategy,
    wrapperStyle: () => ({
      width: 140,
      height: 140,
    }),
    style: { justifyContent: "left" },
  };

  return (
    <div className="App" style={{ padding: "20px" }}>
      <h1>Seating Arranger</h1>

      {guests.length > 0 && (
        <button
          onClick={clearProgress}
          style={{ padding: "8px 16px", marginBottom: "16px" }}
        >
          Start Over
        </button>
      )}

      {guests.length == 0 && (
        <PlainTextForm
          onSubmit={(text: string, tableSize: number) => {
            setGuests(text.split("\n").map((name) => name.trim()));
            setTableSize(tableSize);
          }}
        />
      )}

      {tables == null && <div>Number of guests: {numberOfGuests(guests)} </div>}

      {guests.length > 0 && tables == null && (
        <div style={{ marginTop: "40px" }}>
          {phase === "strong"
            ? "Step 1: Create strong groups by dragging guests over each other. These groups must sit at the same table."
            : "Step 2: Create weak connections between guests or groups. Click a node, then click another to connect them."}
        </div>
      )}

      {guests.length > 0 && tables == null && phase === "strong" && (
        <Sortable
          {...props}
          items={guests}
          onItemsChanged={setGuests}
        />
      )}

      {guests.length > 0 && tables == null && phase === "weak" && (
        <WeakGraph
          nodes={guests}
          edges={weakEdges}
          onEdgesChanged={setWeakEdges}
          nodeColors={nodeColors}
        />
      )}

      {guests.length > 0 && tables == null && (
        <div style={{ maxWidth: "400px", margin: "0 auto" }}>
          {phase === "strong" ? (
            <button
              onClick={() => setPhase("weak")}
              style={{ padding: "8px 16px" }}
            >
              Next
            </button>
          ) : (
            <>
              <button
                onClick={() => setPhase("strong")}
                style={{ padding: "8px 16px", marginRight: "8px" }}
              >
                Back
              </button>
              <button
                onClick={() =>
                  setTables(guestsToTables(guests, tableSize, weakEdges))
                }
                style={{ padding: "8px 16px" }}
              >
                Create Tables
              </button>
            </>
          )}
        </div>
      )}

      {tables && (
        <TablesComponent
          key={tablesKey}
          items={tables}
          maxTableSize={tableSize}
          onItemsChanged={setTables}
          nodeColors={nodeColors}
        />
      )}

      {tables && (
        <div style={{ maxWidth: "400px", margin: "16px auto" }}>
          <button
            onClick={() => {
              if (
                window.confirm(
                  "Are you sure? Going back to the graph view will discard the current table arrangement."
                )
              ) {
                setTables(null);
                setPhase("weak");
              }
            }}
            style={{ padding: "8px 16px", marginRight: "8px" }}
          >
            Go back
          </button>
          <button
            onClick={() => {
              if (
                window.confirm(
                  "Are you sure? Re-solving will erase the current table arrangement."
                )
              ) {
                setTables(guestsToTables(guests, tableSize, weakEdges));
                setTablesKey((k) => k + 1);
              }
            }}
            style={{ padding: "8px 16px" }}
          >
            Re-solve
          </button>
        </div>
      )}

      {tables && (
        <form
          onSubmit={(event) => {
            event.preventDefault();
            const seatingChartByName: string[][] = [];
            const seatingChartByNumber: string[][] = [];
            Object.entries(tables).forEach(([tableNumber, guests]) => {
              guests.forEach((guestGroup) => {
                const guests1 = getAllMembers(guestGroup.toString());
                guests1.forEach((guest) => {
                  seatingChartByName.push([guest.toString(), tableNumber]);
                  seatingChartByNumber.push([guest.toString(), tableNumber]);
                });
              });
            });
            seatingChartByName.sort((a, b) => a[0].localeCompare(b[0]));
            seatingChartByNumber.sort((a, b) => {
              return parseInt(a[1]) - parseInt(b[1]);
            });
            const workbook = XLSX.utils.book_new();
            const worksheetByName = XLSX.utils.aoa_to_sheet(seatingChartByName);
            const worksheetByNumber =
              XLSX.utils.aoa_to_sheet(seatingChartByNumber);
            XLSX.utils.book_append_sheet(
              workbook,
              worksheetByName,
              "Seating Chart By Name"
            );
            XLSX.utils.book_append_sheet(
              workbook,
              worksheetByNumber,
              "Seating Chart By Table Number"
            );
            XLSX.writeFile(workbook, "seating_chart.xlsx");
          }}
          style={{ maxWidth: "400px", margin: "0 auto" }}
        >
          <button type="submit" style={{ padding: "8px 16px" }}>
            Export to Spreadsheet
          </button>
        </form>
      )}
    </div>
  );
}

function numberOfGuests(guests: string[]): number {
  return guests.reduce((total, guest) => {
    return total + groupSize(guest);
  }, 0);
}

export default App;
