import { UniqueIdentifier } from "@dnd-kit/core";
import { groupSize, WeakEdge } from "./groupUtils";
import { Tables } from "./TablesComponent";

// Lexicographic objective:
//   [#single-person strong groups with no weak tablemate,
//    #2+-person strong groups with no weak tablemate,
//    #weak edges broken across tables]
type Cost = [number, number, number];

function compareCost(a: Cost, b: Cost): number {
  if (a[0] !== b[0]) return a[0] - b[0];
  if (a[1] !== b[1]) return a[1] - b[1];
  return a[2] - b[2];
}

function computeComponents(
  nodes: string[],
  neighbors: Map<string, Set<string>>
): string[][] {
  const parent = new Map<string, string>();
  nodes.forEach((n) => parent.set(n, n));

  const find = (x: string): string => {
    let cur = x;
    while (parent.get(cur)! !== cur) {
      const grand = parent.get(parent.get(cur)!)!;
      parent.set(cur, grand);
      cur = grand;
    }
    return cur;
  };

  neighbors.forEach((nbrs, a) => {
    nbrs.forEach((b) => {
      if (!parent.has(b)) return;
      const ra = find(a);
      const rb = find(b);
      if (ra !== rb) parent.set(ra, rb);
    });
  });

  const groups = new Map<string, string[]>();
  nodes.forEach((n) => {
    const root = find(n);
    if (!groups.has(root)) groups.set(root, []);
    groups.get(root)!.push(n);
  });
  return Array.from(groups.values()).filter((g) => g.length > 1);
}

// Enumerate all non-empty subsets of `items` whose total groupSize sums to `target`.
function subsetsSummingTo(items: string[], target: number): string[][] {
  const result: string[][] = [];
  const sizes = items.map((n) => groupSize(n));

  function dfs(idx: number, current: number[], remaining: number) {
    if (remaining === 0) {
      if (current.length > 0) result.push(current.map((i) => items[i]));
      return;
    }
    if (idx >= items.length || remaining < 0) return;
    if (sizes[idx] <= remaining) {
      current.push(idx);
      dfs(idx + 1, current, remaining - sizes[idx]);
      current.pop();
    }
    dfs(idx + 1, current, remaining);
  }
  dfs(0, [], target);
  return result;
}

function ffdPack(guests: string[], tableSize: number): string[][] {
  const sorted = [...guests].sort((a, b) => groupSize(b) - groupSize(a));
  const tables: { items: string[]; size: number }[] = [];
  for (const guest of sorted) {
    const gs = groupSize(guest);
    let placed = false;
    for (const t of tables) {
      if (t.size + gs <= tableSize) {
        t.items.push(guest);
        t.size += gs;
        placed = true;
        break;
      }
    }
    if (!placed) tables.push({ items: [guest], size: gs });
  }
  return tables.map((t) => t.items);
}

function randomPacking(
  guests: string[],
  numTables: number,
  tableSize: number
): string[][] {
  const tables: { items: string[]; size: number }[] = [];
  for (let i = 0; i < numTables; i++) tables.push({ items: [], size: 0 });

  const order = [...guests];
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [order[i], order[j]] = [order[j], order[i]];
  }
  // Place larger groups first so they don't get stuck without room.
  order.sort((a, b) => groupSize(b) - groupSize(a));

  for (const guest of order) {
    const gs = groupSize(guest);
    const feasible: { items: string[]; size: number }[] = [];
    for (const t of tables) if (t.size + gs <= tableSize) feasible.push(t);
    if (feasible.length === 0) {
      tables.push({ items: [guest], size: gs });
    } else {
      const chosen = feasible[Math.floor(Math.random() * feasible.length)];
      chosen.items.push(guest);
      chosen.size += gs;
    }
  }
  return tables.filter((t) => t.items.length > 0).map((t) => t.items);
}

function computeCost(
  tables: string[][],
  neighbors: Map<string, Set<string>>
): Cost {
  let lonelySingle = 0;
  let lonelyMulti = 0;

  for (const table of tables) {
    const tableSet = new Set(table);
    for (const node of table) {
      const nbrs = neighbors.get(node);
      if (!nbrs || nbrs.size === 0) continue;

      let hasNeighborHere = false;
      for (const nbr of Array.from(nbrs)) {
        if (tableSet.has(nbr)) {
          hasNeighborHere = true;
          break;
        }
      }
      if (!hasNeighborHere) {
        if (groupSize(node) === 1) lonelySingle++;
        else lonelyMulti++;
      }
    }
  }

  const nodeToTable = new Map<string, number>();
  tables.forEach((t, i) => t.forEach((n) => nodeToTable.set(n, i)));

  let edgesCut = 0;
  const seenEdges = new Set<string>();
  neighbors.forEach((nbrs, a) => {
    nbrs.forEach((b) => {
      const key = a < b ? `${a}\x00${b}` : `${b}\x00${a}`;
      if (seenEdges.has(key)) return;
      seenEdges.add(key);
      if (nodeToTable.get(a) !== nodeToTable.get(b)) edgesCut++;
    });
  });

  return [lonelySingle, lonelyMulti, edgesCut];
}

function localSearch(
  initial: string[][],
  tableSize: number,
  neighbors: Map<string, Set<string>>,
  components: string[][]
): { tables: string[][]; cost: Cost } {
  const tables = initial.map((t) => [...t]);
  const sizes = tables.map((t) =>
    t.reduce((s, n) => s + groupSize(n), 0)
  );
  let cost = computeCost(tables, neighbors);

  const MAX_PASSES = 200;
  for (let pass = 0; pass < MAX_PASSES; pass++) {
    if (cost[0] === 0 && cost[1] === 0 && cost[2] === 0) break;

    let bestDelta: Cost | null = null;
    let bestApply: (() => void) | null = null;

    // Moves
    for (let i = 0; i < tables.length; i++) {
      for (let ni = 0; ni < tables[i].length; ni++) {
        const node = tables[i][ni];
        const nodeSize = groupSize(node);
        for (let j = 0; j < tables.length; j++) {
          if (i === j) continue;
          if (sizes[j] + nodeSize > tableSize) continue;

          tables[i].splice(ni, 1);
          tables[j].push(node);
          sizes[i] -= nodeSize;
          sizes[j] += nodeSize;

          const newCost = computeCost(tables, neighbors);
          if (compareCost(newCost, cost) < 0) {
            if (bestDelta === null || compareCost(newCost, bestDelta) < 0) {
              bestDelta = newCost;
              const ci = i, cni = ni, cj = j, cnode = node, cns = nodeSize;
              bestApply = () => {
                tables[ci].splice(cni, 1);
                tables[cj].push(cnode);
                sizes[ci] -= cns;
                sizes[cj] += cns;
              };
            }
          }

          tables[j].pop();
          tables[i].splice(ni, 0, node);
          sizes[i] += nodeSize;
          sizes[j] -= nodeSize;
        }
      }
    }

    // Swaps
    for (let i = 0; i < tables.length; i++) {
      for (let ni = 0; ni < tables[i].length; ni++) {
        for (let j = i + 1; j < tables.length; j++) {
          for (let nj = 0; nj < tables[j].length; nj++) {
            const a = tables[i][ni];
            const b = tables[j][nj];
            const aSize = groupSize(a);
            const bSize = groupSize(b);
            if (aSize === bSize && a === b) continue;
            if (sizes[i] - aSize + bSize > tableSize) continue;
            if (sizes[j] - bSize + aSize > tableSize) continue;

            tables[i][ni] = b;
            tables[j][nj] = a;
            sizes[i] = sizes[i] - aSize + bSize;
            sizes[j] = sizes[j] - bSize + aSize;

            const newCost = computeCost(tables, neighbors);
            if (compareCost(newCost, cost) < 0) {
              if (bestDelta === null || compareCost(newCost, bestDelta) < 0) {
                bestDelta = newCost;
                const ci = i, cni = ni, cj = j, cnj = nj;
                const ca = a, cb = b, cas = aSize, cbs = bSize;
                bestApply = () => {
                  tables[ci][cni] = cb;
                  tables[cj][cnj] = ca;
                  sizes[ci] = sizes[ci] - cas + cbs;
                  sizes[cj] = sizes[cj] - cbs + cas;
                };
              }
            }

            tables[i][ni] = a;
            tables[j][nj] = b;
            sizes[i] = sizes[i] + aSize - bSize;
            sizes[j] = sizes[j] + bSize - aSize;
          }
        }
      }
    }

    // Component-aware subset swaps: for each weak component split across
    // tables, try consolidating it onto one table by swapping its outpost
    // members with same-total-size non-component members on that table.
    const nodeToTable = new Map<string, number>();
    tables.forEach((t, idx) => t.forEach((n) => nodeToTable.set(n, idx)));

    for (const component of components) {
      const presence = new Map<number, string[]>();
      for (const node of component) {
        const t = nodeToTable.get(node);
        if (t === undefined) continue;
        if (!presence.has(t)) presence.set(t, []);
        presence.get(t)!.push(node);
      }
      if (presence.size < 2) continue;

      const tableIds = Array.from(presence.keys());
      for (const target of tableIds) {
        const targetMembers = presence.get(target)!;
        const targetMemberSet = new Set(targetMembers);
        const targetNonComponent = tables[target].filter(
          (n) => !targetMemberSet.has(n)
        );

        for (const source of tableIds) {
          if (source === target) continue;
          const sourceMembers = presence.get(source)!;
          const movedSize = sourceMembers.reduce(
            (s, n) => s + groupSize(n),
            0
          );

          const displacements = subsetsSummingTo(
            targetNonComponent,
            movedSize
          );

          for (const D of displacements) {
            const Dset = new Set(D);

            const origSource = tables[source];
            const origTarget = tables[target];
            const newSource = origSource
              .filter((n) => !sourceMembers.includes(n))
              .concat(D);
            const newTarget = origTarget
              .filter((n) => !Dset.has(n))
              .concat(sourceMembers);

            tables[source] = newSource;
            tables[target] = newTarget;
            // Sizes are unchanged (total moved == total displaced).

            const newCost = computeCost(tables, neighbors);
            if (compareCost(newCost, cost) < 0) {
              if (bestDelta === null || compareCost(newCost, bestDelta) < 0) {
                bestDelta = newCost;
                const cs = source;
                const ct = target;
                const cSrcMembers = [...sourceMembers];
                const cD = [...D];
                bestApply = () => {
                  const srcSet = new Set(cSrcMembers);
                  const dSet = new Set(cD);
                  const ns = tables[cs]
                    .filter((n) => !srcSet.has(n))
                    .concat(cD);
                  const nt = tables[ct]
                    .filter((n) => !dSet.has(n))
                    .concat(cSrcMembers);
                  tables[cs] = ns;
                  tables[ct] = nt;
                };
              }
            }

            tables[source] = origSource;
            tables[target] = origTarget;
          }
        }
      }
    }

    if (!bestApply || !bestDelta) break;
    bestApply();
    cost = bestDelta;
  }

  return { tables, cost };
}

export function guestsToTables(
  guests: string[],
  tableSize: number,
  weakEdges: WeakEdge[]
): Tables {
  if (guests.length === 0) return {};

  const neighbors = new Map<string, Set<string>>();
  guests.forEach((g) => neighbors.set(g, new Set()));
  for (const [a, b] of weakEdges) {
    if (neighbors.has(a) && neighbors.has(b)) {
      neighbors.get(a)!.add(b);
      neighbors.get(b)!.add(a);
    }
  }

  const components = computeComponents(guests, neighbors);

  const initial = ffdPack(guests, tableSize);
  const numTables = initial.length;

  let best = initial;
  let bestCost = computeCost(best, neighbors);

  const startingPoints: string[][][] = [initial];
  const RESTARTS = 6;
  for (let r = 0; r < RESTARTS; r++) {
    startingPoints.push(randomPacking(guests, numTables, tableSize));
  }

  for (const start of startingPoints) {
    const { tables, cost } = localSearch(
      start,
      tableSize,
      neighbors,
      components
    );
    if (compareCost(cost, bestCost) < 0) {
      best = tables;
      bestCost = cost;
    }
    if (bestCost[0] === 0 && bestCost[1] === 0 && bestCost[2] === 0) break;
  }

  const out: Tables = {};
  best.forEach((table, i) => {
    out[i + 1] = table as UniqueIdentifier[];
  });
  return out;
}
