import React, { useEffect } from "react";
import classNames from "classnames";
import {
  UniqueIdentifier,
  useDndContext,
  type DraggableSyntheticListeners,
} from "@dnd-kit/core";
import type { Transform } from "@dnd-kit/utilities";

import { Remove, Ungroup } from "./components";
import { getAllMembers, isGroup } from "../../groupUtils";

import styles from "./Item.module.scss";

export interface Props {
  dragOverlay?: boolean;
  dragging?: boolean;
  index?: number;
  fadeIn?: boolean;
  transform?: Transform | null;
  listeners?: DraggableSyntheticListeners;
  sorting?: boolean;
  style?: React.CSSProperties;
  transition?: string | null;
  value: string;
  onRemove?(): void;
  onUngroup?(): void;
}

export const Item = React.memo(
  React.forwardRef<HTMLDivElement, Props>(
    (
      {
        dragOverlay,
        dragging,
        fadeIn,
        index,
        listeners,
        onRemove,
        onUngroup,
        sorting,
        style,
        transition,
        transform,
        value,
        ...props
      },
      ref
    ) => {
      useEffect(() => {
        if (!dragOverlay) {
          return;
        }

        document.body.style.cursor = "grabbing";

        return () => {
          document.body.style.cursor = "";
        };
      }, [dragOverlay]);

      const { collisions } = useDndContext();
      const isHovered =
        collisions?.find((collision) => collision.id === value)?.data
          ?.hovered || false;

      const allGuests = getAllMembers(value);
      const grouped = isGroup(value);

      const wrapperStyle = {
        transition: [transition, null].filter(Boolean).join(", "),
        "--translate-x": transform
          ? `${Math.round(transform.x)}px`
          : undefined,
        "--translate-y": transform
          ? `${Math.round(transform.y)}px`
          : undefined,
        "--scale-x": transform?.scaleX
          ? `${transform.scaleX}`
          : undefined,
        "--scale-y": transform?.scaleY
          ? `${transform.scaleY}`
          : undefined,
        "--index": index,
        border: isHovered
          ? "2px solid #66FF99"
          : "2px solid #FFFFFF",
      } as React.CSSProperties;

      const renderGuest = (guest: string, isFirst: boolean) => (
        <li
          key={guest}
          className={classNames(
            styles.Wrapper,
            fadeIn && styles.fadeIn,
            sorting && styles.sorting,
            dragOverlay && styles.dragOverlay
          )}
          style={wrapperStyle}
        >
          <div
            className={classNames(
              styles.Item,
              dragging && styles.dragging,
              dragOverlay && styles.dragOverlay,
            )}
            style={style}
            data-cypress="draggable-item"
            {...listeners}
            {...props}
            tabIndex={0}
          >
            {guest}
            <span className={styles.Actions}>
              {onUngroup && grouped && isFirst ? (
                <Ungroup className={styles.Remove} onPointerDown={(e) => e.stopPropagation()} onMouseDown={(e) => e.stopPropagation()} onClick={onUngroup} />
              ) : null}
              {onRemove ? (
                <Remove className={styles.Remove} onClick={onRemove} />
              ) : null}
            </span>
          </div>
        </li>
      );

      return (
        <div ref={ref} style={{ gridRow: "span " + allGuests.length }}>
          {allGuests.map((guest, i) => renderGuest(guest, i === 0))}
        </div>
      );
    }
  )
);
