/**
 * Group encoding:
 *   ","  separates individuals within a strong group (must sit together)
 *
 * Weak connections are stored separately as edges in a graph.
 *
 * Examples:
 *   "Alice"             — single guest
 *   "Alice,Bob"         — strong group (couple)
 */

export type WeakEdge = [string, string];

/** Whether this item is any kind of group (more than one person) */
export function isGroup(value: string): boolean {
  return getAllMembers(value).length > 1;
}

/** Get every individual name from a group encoding */
export function getAllMembers(value: string): string[] {
  return value.split(",");
}

/** Total number of individuals in this item */
export function groupSize(value: string): number {
  return getAllMembers(value).length;
}

/**
 * Merge two items into a strong group with ","
 */
export function mergeItems(a: string, b: string): string {
  return a + "," + b;
}

/**
 * Ungroup: split a strong group into individuals.
 *   "A,B,C" → ["A", "B", "C"]
 *   "A" → ["A"] (no-op)
 */
export function ungroupItem(value: string): string[] {
  return value.split(",");
}
