import { useMemo, useRef } from "react";
import { WeakEdge, groupSize } from "./groupUtils";

function computeComponents(nodes: string[], edges: WeakEdge[]): string[][] {
  const parent = new Map<string, string>();
  nodes.forEach((n) => parent.set(n, n));

  const find = (x: string): string => {
    let cur = x;
    while (parent.get(cur)! !== cur) {
      const grand = parent.get(parent.get(cur)!)!;
      parent.set(cur, grand);
      cur = grand;
    }
    return cur;
  };

  edges.forEach(([a, b]) => {
    if (parent.has(a) && parent.has(b)) {
      const ra = find(a);
      const rb = find(b);
      if (ra !== rb) parent.set(ra, rb);
    }
  });

  const groups = new Map<string, string[]>();
  nodes.forEach((n) => {
    const root = find(n);
    if (!groups.has(root)) groups.set(root, []);
    groups.get(root)!.push(n);
  });
  return Array.from(groups.values());
}

function componentKey(component: string[]): string {
  return [...component].sort().join("\x00");
}

function randomPastel(existingColors: string[]): string {
  const existingHues: number[] = [];
  existingColors.forEach((c) => {
    const m = c.match(/hsl\(\s*([\d.]+)/);
    if (m) existingHues.push(parseFloat(m[1]));
  });

  let bestHue = Math.random() * 360;
  if (existingHues.length > 0) {
    let bestDist = -1;
    for (let i = 0; i < 36; i++) {
      const h = (i * 10 + Math.random() * 5) % 360;
      let minDist = 360;
      for (const eh of existingHues) {
        const d = Math.min(Math.abs(h - eh), 360 - Math.abs(h - eh));
        minDist = Math.min(minDist, d);
      }
      if (minDist > bestDist) {
        bestDist = minDist;
        bestHue = h;
      }
    }
  }

  return `hsl(${Math.round(bestHue)}, 65%, 82%)`;
}

export function useGroupColors(
  nodes: string[],
  edges: WeakEdge[]
): Map<string, string> {
  const prevComponentsRef = useRef<Map<string, string[]>>(new Map());
  const prevColorsRef = useRef<Map<string, string>>(new Map());

  return useMemo(() => {
    const components = computeComponents(nodes, edges);
    const prevComponents = prevComponentsRef.current;
    const prevColors = prevColorsRef.current;
    const newColors = new Map<string, string>();

    const nodeToNewKey = new Map<string, string>();
    components.forEach((c) => {
      const key = componentKey(c);
      c.forEach((n) => nodeToNewKey.set(n, key));
    });

    // For each previous colored component, find its primary heir: the new
    // component sharing the most members. Only that heir inherits the old
    // color; other pieces of a split must take new colors.
    const heir = new Map<string, string>();
    prevComponents.forEach((prevNodes, prevKey) => {
      if (!prevColors.has(prevKey)) return;

      const shareMap = new Map<string, number>();
      prevNodes.forEach((node) => {
        const newKey = nodeToNewKey.get(node);
        if (newKey) {
          shareMap.set(newKey, (shareMap.get(newKey) || 0) + groupSize(node));
        }
      });

      let bestNewKey: string | null = null;
      let bestShare = 0;
      Array.from(shareMap.entries())
        .sort((a, b) => a[0].localeCompare(b[0]))
        .forEach(([newKey, share]) => {
          if (share > bestShare) {
            bestShare = share;
            bestNewKey = newKey;
          }
        });

      if (bestNewKey) heir.set(prevKey, bestNewKey);
    });

    components.forEach((component) => {
      if (component.length <= 1) return;
      const key = componentKey(component);

      let bestColor: string | null = null;
      let bestPrevSize = 0;
      heir.forEach((newKey, prevKey) => {
        if (newKey !== key) return;
        const prevNodes = prevComponents.get(prevKey) || [];
        const prevSize = prevNodes.reduce((s, n) => s + groupSize(n), 0);
        if (prevSize > bestPrevSize) {
          bestPrevSize = prevSize;
          bestColor = prevColors.get(prevKey) || null;
        }
      });

      if (bestColor) newColors.set(key, bestColor);
    });

    components.forEach((component) => {
      if (component.length <= 1) return;
      const key = componentKey(component);
      if (!newColors.has(key)) {
        newColors.set(key, randomPastel(Array.from(newColors.values())));
      }
    });

    prevComponentsRef.current = new Map(
      components.map((c) => [componentKey(c), c])
    );
    prevColorsRef.current = newColors;

    const nodeColorMap = new Map<string, string>();
    components.forEach((component) => {
      const key = componentKey(component);
      const color = newColors.get(key);
      if (color) component.forEach((n) => nodeColorMap.set(n, color));
    });
    return nodeColorMap;
  }, [nodes, edges]);
}
